awk '/run: \|/{print "      run: |\n        echo \"${{ secrets.SIGNING_KEY_BASE64 }}\" | base64 -d > secring.gpg\n        export ORG_GRADLE_PROJECT_signingInMemoryKey=$(cat secring.gpg)\n        ./gradlew publishAndReleaseToMavenCentral"; next} /key=\$\(echo/{next} /export ORG_GRADLE_PROJECT_signingInMemoryKey="\$key"/{next} /.\/gradlew publishAndReleaseToMavenCentral/{next} {print}' .github/workflows/ci.yml > tmp.yml && mv tmp.yml .github/workflows/ci.yml
